            AuditEntry(
                flowInstanceId = task.flowInstanceId,
                taskId = task.id,
                type = AuditEventType.TASK_CLAIMED,
                actorId = command.actor.actorId,
                occurredAt = now,
            )
        )

        return ClaimTaskResult.Success(claimedTask)
    }
}

