// Swap in a Testcontainers Postgres for the generateJooq task so no running DB is needed.
tasks.named<nu.studer.gradle.jooq.JooqGenerate>("generateJooq") {
    val migrationsDir = file("src/main/resources/db/migration")
    inputs.dir(migrationsDir)
    outputs.dir("build/generated-src/jooq/main")

    doFirst {
        @Suppress("UNCHECKED_CAST")
        val pg = org.testcontainers.containers.PostgreSQLContainer<Nothing>("postgres:16-alpine").apply {
            withDatabaseName("wrkflw_codegen")
            withUsername("wrkflw")
            withPassword("wrkflw")
            start()
        }

        org.flywaydb.core.Flyway.configure()
            .dataSource(pg.jdbcUrl, pg.username, pg.password)
            .locations("filesystem:${migrationsDir.absolutePath}")
            .load()
            .migrate()

        jooqConfiguration.jdbc.apply {
            url = pg.jdbcUrl
            user = pg.username
            password = pg.password
        }

        // Stash the container so doLast can stop it
        project.extensions.extraProperties["_jooqPgContainer"] = pg
    }

    doLast {
        (project.extensions.extraProperties["_jooqPgContainer"]
                as? org.testcontainers.containers.PostgreSQLContainer<*>)?.stop()
    }
}

