        testEnv.sleep(java.time.Duration.ofMillis(500))

        val pendingTasks = runBlocking { tasks.findByFlowInstanceId(instance.id) }
        pendingTasks shouldHaveSize 1
        val task = pendingTasks.first()

        val claimResult = runBlocking { claimTask.execute(ClaimTaskCommand(task.id, reviewerActor())) }
        claimResult.shouldBeInstanceOf<ClaimTaskResult.Success>()

        val decisionResult = runBlocking {
            submitDecision.execute(SubmitDecisionCommand(task.id, DecisionOutcome.APPROVE, "Looks good", reviewerActor()))
        }
        decisionResult.shouldBeInstanceOf<SubmitDecisionResult.Success>()
        val updatedInstance = (decisionResult as SubmitDecisionResult.Success).flowInstance
        updatedInstance.status shouldBe FlowStatus.COMPLETED
        updatedInstance.terminalOutcome shouldBe "APPROVED"

        val finalTask = runBlocking { tasks.findById(task.id)!! }
        finalTask.status shouldBe TaskStatus.COMPLETED

        val decision = runBlocking { decisions.findByTaskId(task.id)!! }
        decision.outcome shouldBe DecisionOutcome.APPROVE
        decision.comment shouldBe "Looks good"
    }

    @Test
    fun `non-owner attempting to decide returns Forbidden`() {
        val submitResult = runBlocking {
            submitDocument.execute(SubmitDocumentCommand("document-approval", "doc-002", authorActor()))
        }
        val instance = (submitResult as SubmitDocumentResult.Success).instance
        testEnv.sleep(java.time.Duration.ofMillis(500))

        val task = runBlocking { tasks.findByFlowInstanceId(instance.id) }.first()

        // reviewer1 claims it
        runBlocking { claimTask.execute(ClaimTaskCommand(task.id, reviewerActor("reviewer1"))) }

        // reviewer2 tries to decide
        val result = runBlocking {
            submitDecision.execute(SubmitDecisionCommand(task.id, DecisionOutcome.APPROVE, null, reviewerActor("reviewer2")))
        }
        result shouldBe SubmitDecisionResult.Forbidden
